-- Validation test updates
UPDATE "public"."dev_lessons" SET "title" = 'Firmeza em Meio à Multidão', "biblical_story" = 'Sadraque, Mesaque e Abednego encontravam-se na planície de Dura, diante do rei Nabucodonosor. Uma estátua de ouro impunha adoração a todos os súditos sob pena de morte na fornalha ardente. Ao som de harpas e trombetas, a multidão prostrou-se, mas os três jovens hebreus permaneceram de pé. Confrontados pela ira do rei, que os questionou sobre sua desobediência, eles não recuaram. Com clareza e firmeza, responderam que o Deus a quem serviam era capaz de livrá-los da fornalha. Declararam que, ainda que Ele não o fizesse, jamais serviriam aos deuses do rei ou adorariam a estátua que ele levantara. Eles não buscaram uma saída fácil, nem negociaram seus princípios. Mantiveram sua postura diante do poder humano, escolhendo a obediência absoluta ao Criador acima da própria vida. Naquele momento, sua fé tornou-se o testemunho mais eloquente perante o império babilônico, provando que a verdadeira lealdade não se curva perante ameaças.', "reflection" = 'Muitas vezes, a pressão para se conformar não vem de um rei com uma fornalha, mas do silêncio cúmplice diante de uma piada maldosa ou da necessidade de seguir a maioria para não ser excluído da turma. A coragem de Daniel e seus amigos não nasceu de uma força sobre-humana, mas da convicção de que sua lealdade a Deus era inegociável. Ser fiel ao que é certo, mesmo quando todos ao redor escolhem o caminho contrário, é o que define um caráter firme. Coragem real é a decisão de sustentar seus valores morais quando o medo sugere que o caminho mais fácil é ceder.', "challenge" = 'Hoje, escolha defender a verdade em um momento onde todos optarem pelo silêncio.', "final_message" = 'Sua fidelidade a Deus vale muito mais que a aprovação alheia.' WHERE "id" = '007e8630-e9e5-4d72-b59b-b1a57f96c090';
UPDATE "public"."dev_lessons" SET "title" = 'A Inabalável Convicção de Daniel', "biblical_story" = 'O rei Nabucodonosor ergueu uma estátua de ouro na província de Babilônia e convocou todas as autoridades para a cerimônia de dedicação. Um edito real determinou que, ao som de instrumentos musicais, todos deveriam se prostrar diante da imagem, sob pena de morte na fornalha ardente. Sadraque, Mesaque e Abede-Nego, oficiais judeus, recusaram-se a curvar-se. Confrontados pelo rei furioso, eles não negociaram. Responderam com firmeza que o Deus a quem serviam era capaz de livrá-los, mas, ainda que Ele escolhesse não o fazer, eles jamais adorariam ídolos. A postura deles não foi um ato impulsivo de rebeldia, mas uma decisão inabalável baseada na fidelidade a Deus. Enquanto a multidão se prostrava em uníssono, os três amigos mantiveram-se de pé, enfrentando a autoridade máxima do império com a tranquilidade de quem já havia entregado o resultado final nas mãos do Senhor.', "reflection" = 'A pressão da multidão é um teste severo para a integridade do homem. Quando o barulho ao redor tenta ditar nosso curso, o medo de ser diferente nos empurra para o conformismo. Sadraque, Mesaque e Abede-Nego não hesitaram porque já haviam decidido obedecer a Deus muito antes do momento da prova. A verdadeira firmeza não surge diante da fornalha, mas é cultivada no silêncio da obediência diária. Quem não estabelece seus princípios no particular será inevitavelmente arrastado pela correnteza da vontade alheia. A integridade exige que o governo da sua conduta pertença exclusivamente ao Altíssimo.', "challenge" = 'Defina hoje um princípio inegociável e escreva como você o manterá em situações difíceis.', "final_message" = 'A obediência silenciosa prepara o homem para os grandes confrontos.' WHERE "id" = '00ff9dc6-f0df-4755-ab45-3336f120839e';
UPDATE "public"."dev_lessons" SET "title" = 'O Caminho do Retorno Sincero', "biblical_story" = 'Longe de casa, o filho que exigiu sua herança encontrou apenas a miséria. Ao se ver cuidando de porcos e faminto, algo mudou em seu coração. O texto narra que ele caiu em si. Ele não buscou desculpas para sua dissipação, nem culpou o destino por sua escassez. Em vez disso, lembrou-se da provisão e da bondade na casa de seu pai, onde até os empregados viviam com dignidade. Tomou, então, a decisão firme: levantou-se e iniciou a longa caminhada de volta. Enquanto ainda estava longe, o pai, que esperava ansiosamente, correu ao seu encontro, abraçou-o e o beijou. O filho reconheceu sua falta, mas o pai não esperou pelo fim do discurso. Ordenou prontamente que lhe dessem as melhores vestes e celebrassem seu retorno, pois aquele que estava morto havia retornado à vida.', "reflection" = 'O retorno do filho pródigo não foi movido por conveniência, mas por um reconhecimento humilde da própria falha. Para vocês, jovens e pais, isso significa entender que a maturidade cristã é provada na decisão de abandonar o erro quando ninguém está olhando. O arrependimento exige coragem para trocar o orgulho pela verdade, reconhecendo que a restauração é uma dádiva do Pai que excede nossa capacidade de merecer. Quando um erro acontece, a prioridade não deve ser esconder o estrago, mas buscar a reconciliação com a mesma prontidão com que o filho correu para o perdão.', "challenge" = 'Hoje, peça perdão a alguém por um erro que você tentou esconder ou minimizar.', "final_message" = 'O arrependimento é o primeiro passo para uma vida restaurada.' WHERE "id" = '0118f762-7f79-4ccc-a111-dc130891a1a9';
UPDATE "public"."dev_lessons" SET "title" = 'Coragem Firme na Fornalha', "biblical_story" = 'O rei Nabucodonosor ergueu uma colossal estátua de ouro na província de Babilônia e decretou que, ao som de instrumentos musicais, todos deveriam se prostrar e adorá-la. A ordem era clara: quem desobedecesse seria imediatamente lançado em uma fornalha ardente. Sadraque, Mesaque e Abednego, jovens judeus que serviam ao rei, recusaram-se a dobrar os joelhos diante do ídolo. Confrontados pelo monarca enfurecido, que lhes deu uma última chance, eles não tremeram diante da ameaça de morte. Com serenidade, responderam que o Deus a quem serviam era capaz de livrá-los da fornalha, mas enfatizaram que, mesmo que Ele decidisse não o fazer, jamais serviriam aos deuses babilônicos nem adorariam a imagem de ouro. Diante do homem mais poderoso do mundo, esses três homens mantiveram sua lealdade exclusiva ao Criador, escolhendo a fidelidade absoluta acima da própria sobrevivência, desafiando a autoridade humana com um ''não'' inabalável.', "reflection" = 'O medo é a arma principal de quem deseja controlar suas escolhas. Hoje, a fornalha não é de fogo, mas é feita de escárnio, isolamento ou perda de popularidade entre seus amigos. Os três jovens não improvisaram sua fé no momento do perigo; eles haviam decidido quem eram muito antes do rei dar a ordem. A verdadeira força de um jovem não está em sua capacidade de evitar problemas, mas na firmeza de seus limites morais quando ninguém, exceto Deus, está observando. Decida hoje o seu ''não'' antes que a pressão chegue.', "challenge" = 'Diga ''não'' hoje a uma atitude comum no seu grupo que ofende a Deus.', "final_message" = 'Sua obediência a Deus vale mais que o aplauso dos homens.' WHERE "id" = '01d8a7a3-46a4-4783-ba2d-adcf08894f4c';
UPDATE "public"."dev_lessons" SET "title" = 'Confiança que Guia o Futuro', "biblical_story" = 'O rei Salomão, ainda jovem ao assumir o trono de Israel, reconheceu que a sua própria inteligência era insuficiente para liderar um povo tão vasto. Diante de Deus, ele não buscou glória pessoal, riquezas ou a eliminação de seus opositores. Em vez disso, demonstrou temor e humildade, pedindo sabedoria para governar com justiça e discernir entre o bem e o mal. Ao escrever posteriormente o conselho contido em Provérbios 3:5-6, Salomão revelou o segredo de sua trajetória: confiar inteiramente no Senhor e não se apoiar no próprio entendimento. Ele compreendeu que a vida não é um projeto que controlamos com base em nossa limitada visão, mas uma caminhada guiada por Aquele que conhece o início e o fim. Ao submeter suas escolhas ao discernimento divino, Salomão encontrou o caminho seguro para edificar um reino sólido, equilibrado pelo respeito aos mandamentos e pela obediência constante.', "reflection" = 'Muitas vezes, a ansiedade juvenil surge do desejo de antecipar o futuro e controlar os resultados das suas decisões antes do tempo. Quando você tenta traçar seu destino confiando apenas na sua perspicácia, o peso das escolhas se torna um fardo insuportável. A verdadeira segurança não vem de ter todas as respostas ou garantias de sucesso, mas de reconhecer que Deus conhece o seu caminho melhor do que você. Viver sob essa confiança significa fazer escolhas honestas hoje, pautadas em princípios que não mudam, permitindo que a sabedoria divina oriente seus passos mesmo quando o amanhã parece incerto.', "challenge" = 'Abra mão de um plano pessoal hoje e peça a direção de Deus em oração.', "final_message" = 'Quem confia em Deus não precisa temer os seus próprios passos.' WHERE "id" = '01e7f6cf-156e-409b-954e-4801d2323710';
